<span class="line"><span style="color:#ABB2BF;">  </span><span style="color:#E06C75;">&quot;main&quot;</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">&quot;dist/ts-axios.umd.js&quot;</span><span style="color:#ABB2BF;">,</span></span>
